mapper.insert:
INSERT INTO reservation
    SET user_id = #{userId}
    , facility_id = #{facilityId}
    , reservation_date = #{reservationDate}
    ,start_time = #{startTime}
    , end_time = #{endTime}
    , seat_no =  #{seatNo}
    , program_id = #{programId}
    , status = #{status}

mapper.select:
SELECT COUNT(*)
FROM reservation r
JOIN facility f ON r.facility_id = f.facility_id
JOIN user u ON r.user_id = u.user_id
LEFT JOIN household h ON h.household_id = u.household_id


        AND r.status = #{status}


        AND f.name LIKE CONCAT('%', #{facilityName}, '%')


        AND r.facility_id = #{facilityId}


        AND r.reservation_date = #{reservationDate}


        AND u.name LIKE CONCAT('%', #{userName}, '%')

SELECT r.reservation_id, r.reservation_date, r.start_time, r.end_time, r.seat_no, r.status, r.created_at, r.cancelled_at, r.program_id, r.approved_at, f.facility_id, f.name AS facilityName, f.max_capacity, u.user_id, u.name AS userName, h.dong, h.ho, (SELECT COUNT(*) FROM reservation r2 WHERE r2.facility_id = r.facility_id AND r2.reservation_date = r.reservation_date AND r2.start_time = r.start_time AND r2.status = 'CONFIRMED') AS currentCount, (SELECT COUNT(*) FROM reservation r2 WHERE r2.program_id = r.program_id AND r2.status = 'PENDING' AND r.program_id IS NOT NULL) AS pendingCount FROM reservation r JOIN facility f ON r.facility_id = f.facility_id JOIN user u ON r.user_id = u.user_id LEFT JOIN household h ON h.household_id = u.household_id
AND r.status = #{status}
AND f.name LIKE CONCAT('%', #{facilityName}, '%')
AND r.facility_id = #{facilityId}
AND r.reservation_date = #{reservationDate}
AND u.name LIKE CONCAT('%', #{userName}, '%')
ORDER BY r.reservation_date DESC, r.start_time DESC LIMIT #{startIdx}, #{size}
